Connect-MgGraph -Scopes 'Policy.ReadWrite.CrossTenantAccess'

# Configure the default outbound policy to enforce tenant restrictions
# This tells Entra ID what to do when it sees the Restrict-Access-Context header
Update-MgPolicyCrossTenantAccessPolicyDefault -BodyParameter @{
    tenantRestrictions = @{
        usersAndGroups = @{
            accessType   = 'allowed'
            targets      = @(@{ target = 'AllUsers'; targetType = 'user' })
        }
        applications = @{
            accessType = 'allowed'
            targets    = @(@{ target = 'AllApplications'; targetType = 'application' })
        }
    }
}
Write-Host 'Default tenant restriction policy configured.'

Connect-MgGraph -Scopes 'Policy.ReadWrite.CrossTenantAccess'

# Configure tenant restrictions v2 on the cross-tenant access default policy
# TRv2 uses a different property: tenantRestrictions with an 'allowed' tenant list
$allowedTenants = @(
    @{ tenantId = '<your-org-tenant-id>';   tenantName = 'Contoso' }
    @{ tenantId = '<partner-tenant-id>';     tenantName = 'Partner Corp' }
)

# Also specify which applications to restrict
Invoke-MgGraphRequest -Method PATCH `
    -Uri 'https://graph.microsoft.com/v1.0/policies/crossTenantAccessPolicy/default' `
    -Body (@{
        tenantRestrictions = @{
            usersAndGroups = @{
                accessType = 'blocked'
                targets    = @(@{ target = 'AllUsers'; targetType = 'user' })
            }
            applications = @{
                accessType = 'blocked'
                targets    = @(@{ target = 'AllApplications'; targetType = 'application' })
            }
        }
    } | ConvertTo-Json -Depth 5) `
    -ContentType 'application/json'
Write-Host 'TRv2 blocking policy set on default cross-tenant access policy.'

Connect-MgGraph -Scopes 'Policy.ReadWrite.CrossTenantAccess'

# Allow specific access to a partner tenant (exception to the default block)
$partnerTenantId = '<partner-tenant-id>'

# Create a partner-specific CTAS entry
Invoke-MgGraphRequest -Method POST `
    -Uri 'https://graph.microsoft.com/v1.0/policies/crossTenantAccessPolicy/partners' `
    -Body (@{
        tenantId = $partnerTenantId
        tenantRestrictions = @{
            usersAndGroups = @{
                accessType = 'allowed'
                targets    = @(@{ target = 'AllUsers'; targetType = 'user' })
            }
            applications = @{
                accessType = 'allowed'
                targets    = @(@{ target = 'AllApplications'; targetType = 'application' })
            }
        }
    } | ConvertTo-Json -Depth 5) `
    -ContentType 'application/json'
Write-Host "Per-partner exception created for tenant: $partnerTenantId"

Connect-MgGraph -Scopes 'Policy.ReadWrite.CrossTenantAccess'

# View current cross-tenant access default settings
$defaults = Get-MgPolicyCrossTenantAccessPolicyDefault
Write-Host 'Current TR settings:' ($defaults | ConvertTo-Json -Depth 5)

# Block all inbound sessions from other tenants (employees cannot sign in to external tenants)
# Note: This sets the DEFAULT policy — affects all external tenants not listed in partner settings
Update-MgPolicyCrossTenantAccessPolicyDefault -BodyParameter @{
    TenantRestrictions = @{
        UsersAndGroups = @{
            AccessType = 'blocked'
            Targets    = @(
                @{ Target = 'AllUsers'; TargetType = 'user' }
            )
        }
        Applications = @{
            AccessType = 'blocked'
            Targets    = @(
                @{ Target = 'AllApplications'; TargetType = 'application' }
            )
        }
    }
}
Write-Host 'TRv2 default policy updated — all external tenant access blocked.'

Connect-MgGraph -Scopes 'Policy.ReadWrite.CrossTenantAccess'

# Allow employees to authenticate to a specific approved partner tenant
$partnerTenantId = 'bbbbcccc-0000-1111-2222-ddddeeeeeeee'

# Create a partner-specific cross-tenant access policy
New-MgPolicyCrossTenantAccessPolicyPartner -BodyParameter @{
    TenantId = $partnerTenantId
    TenantRestrictions = @{
        UsersAndGroups = @{
            AccessType = 'allowed'
            Targets    = @(
                @{ Target = 'AllUsers'; TargetType = 'user' }
            )
        }
        Applications = @{
            AccessType = 'allowed'
            Targets    = @(
                @{ Target = 'AllApplications'; TargetType = 'application' }
            )
        }
    }
}
Write-Host "Per-tenant exception added for $partnerTenantId"

# List all configured partner policies
Get-MgPolicyCrossTenantAccessPolicyPartner | Format-Table TenantId, IsServiceProvider
